import React, { useMemo } from "react";
import { AdvancedMarker } from "@vis.gl/react-google-maps";
import type { Stop } from "@moventis/db";
import { Bus } from "lucide-react";
import { Badge } from "@/components/ui/badge";

interface MapPinProps {
  stop: Stop;
  zoomBucket: "small" | "medium" | "large";
  isSelected: boolean;
  onClick: (stop: Stop) => void;
}

const MapPin = React.memo(
  ({ stop, zoomBucket, isSelected, onClick }: MapPinProps) => {
    // Check if the stop is newer than 14 days
    const isNew = useMemo(() => {
      if (!stop.createdAt) return false;

      const fourteenDaysInMs = 14 * 24 * 60 * 60 * 1000;
      const ageInMs = Date.now() - new Date(stop.createdAt).getTime();

      return ageInMs < fourteenDaysInMs;
    }, [stop.createdAt]);

    if (zoomBucket === "small") {
      return (
        <AdvancedMarker
          position={{ lat: stop.latitude, lng: stop.longitude }}
          onClick={() => onClick(stop)}
          zIndex={isSelected ? 10 : 1}
        >
          <div className="size-2.5 rounded-full bg-blue-500 opacity-70" />
        </AdvancedMarker>
      );
    }

    if (zoomBucket === "medium") {
      return (
        <AdvancedMarker
          position={{ lat: stop.latitude, lng: stop.longitude }}
          onClick={() => onClick(stop)}
          title={stop.name}
          zIndex={isSelected ? 10 : 1}
        >
          <div
            className={`relative flex size-7 items-center justify-center rounded-full border-2 border-white bg-blue-600 text-white shadow-lg transition-all hover:scale-110 ${isSelected ? "scale-105 bg-blue-800 ring-4 ring-blue-300" : ""} `}
          >
            {isNew && (
              <Badge className="absolute -top-4 left-1/2 z-20 flex h-5 -translate-x-1/2 items-center justify-center rounded-full border-2 border-white bg-red-500 px-1.5 text-xs font-extrabold text-white shadow-sm hover:bg-red-600">
                new
              </Badge>
            )}
            <Bus size={16} />
          </div>
        </AdvancedMarker>
      );
    }

    return (
      <AdvancedMarker
        position={{ lat: stop.latitude, lng: stop.longitude }}
        onClick={() => onClick(stop)}
        title={stop.name}
        zIndex={isSelected ? 10 : 1}
      >
        <div
          className="absolute"
          style={{ transform: "translate(-50%, -100%)" }}
        >
          <div
            className={`group relative flex cursor-pointer flex-col items-center transition-transform hover:scale-110! ${isSelected ? "scale-105" : "scale-100"} `}
          >
            {isNew && (
              <Badge className="absolute -top-3 left-1/2 z-20 flex h-5 -translate-x-1/2 items-center justify-center rounded-full border-2 border-white bg-red-500 px-1.5 font-bold tracking-wider text-white shadow-sm hover:bg-red-600">
                new
              </Badge>
            )}
            <div
              className={`z-10 flex h-10 w-10 items-center justify-center rounded-full border-2 border-white bg-blue-600 text-white shadow-lg ${isSelected ? "bg-blue-800 ring-4 ring-blue-300" : ""} `}
            >
              <Bus size={22} />
            </div>
            <div
              className={`z-0 h-4 w-4 -translate-y-2.5 rotate-45 transform bg-blue-600 ${isSelected ? "bg-blue-800" : ""} `}
            />
          </div>
        </div>
      </AdvancedMarker>
    );
  },
);

MapPin.displayName = "MapPin";

export default MapPin;
